import MDAnalysis
import os
import shutil
import subprocess
#from mbuild.utils.jsutils import overwrite_nglview_default




def adapt_to_nbZIFFF(pdb_filepath,force_field_lib_path,output_folder):
    '''
    Adapts a PDB file to nbZIFFF LAMMPS data file format (nbZIFFF_sorted.data)
    Also generates nbZIFFF_vis.pdb for visualization
    
    Parameters
    ----------
    pdb_filepath : str 
        Path to input PDB file
    force_field_lib_path : str
        Path to force field library file
    output_folder : str
        Path to output directory
    mode : str
        Mode to run the function
        'default' : default mode using the code from the original nbZIFFF
        'new': written by my self in python
        
    This function:
    1. Creates output directory if it doesn't exist
    2. Corrects element types in PDB file (ZN -> Zn)
    3. Copies force field library to output folder (Required by cif2lammps)
    4. Converts PDB to CIF using pdb2cif
    5. Converts CIF to LAMMPS data file using cif2lammps
    6. Sorts atom types in lmp-data file to a fixed order
    7. Writes final nbZIFFF_sorted.data file and nbZIFFF_vis.pdb for visualization
    '''
    def correct_element_types_PDB(filename):
        '''MDanalysis would output ZN instead of Zn in the element part of PDB file.
        This function corrects the element types in the PDB file for other programs to correctly read the file.
        '''
        with open(filename, 'r') as f:
            lines = f.readlines()
        for enum in range(len(lines)):
            if lines[enum].startswith('ATOM'):
                if lines[enum][76:78] == 'ZN':
                    lines[enum] = lines[enum][0:76] + 'Zn' + lines[enum][78:]
        with open(filename, 'w') as f:
            f.writelines(lines)
    if not os.path.exists(output_folder):
        os.mkdir(output_folder)
    correct_element_types_PDB(pdb_filepath)
    shutil.copy(force_field_lib_path,os.path.join(output_folder,'forcefield.lib'))
    pdb2cif='/scratch/zbai29/data_JR/ZIFWTMetaDnbZIFFF/Codes/PrepareCIFFiles_AddSolventSurface_AddDummytoms/pdb2cif_log_node'
    cif2lammps='/scratch/zbai29/data_JR/ZIFWTMetaDnbZIFFF/Codes/Prepare_LAMMPS_Inputs/cif2lammps_log_node'
    pdb2ciflog=os.path.join(output_folder,'pdb2cif.log')
    # Run pdb2cif command
    with open(pdb_filepath, 'r') as infile:
        with open(pdb2ciflog, 'w') as outfile:
            subprocess.run([pdb2cif], stdin=infile, stdout=outfile, stderr=outfile,cwd=output_folder)
    # Set output cif path and move file
    cifpath = os.path.join(output_folder, 'nbZIFFF.cif')
    os.rename(os.path.join(output_folder, 'p1_fromPDBFile.cif'), cifpath)
    
    # Run cif2lammps command
    cif2lammpslogpath = os.path.join(output_folder, 'cif2lammps.log')
    with open(cif2lammpslogpath, 'w') as outfile:
        subprocess.run([cif2lammps, '-i', 'nbZIFFF.cif', '--cif', 'nbZIFFF.cif', 
                       '--no-charges', '--search-and-modify-topology', '--lammps'],
                      stdout=outfile, stderr=outfile,cwd=output_folder)
    u = MDAnalysis.Universe(os.path.join(output_folder, 'nbZIFFF.data'), format="DATA",in_memory=True)

    # generate nbZIFFF_vis.pdb
    with open(os.path.join(output_folder, 'atom_types_for_dump.txt'), 'r') as f:
        atom_types=f.readline().split()
    u.atoms.types=[atom_types[int(i)-1] for i in u.atoms.types]
    u.add_TopologyAttr("element", u.atoms.types)
    u.add_TopologyAttr("name", u.atoms.types)
    u.atoms.write(os.path.join(output_folder, 'nbZIFFF_vis.pdb'),file_format="PDB")
    correct_element_types_PDB(os.path.join(output_folder, 'nbZIFFF_vis.pdb'))
    #sort atom types to a fixed order
    u=convert_atom_types(u,'int')
    u.atoms.write(os.path.join(output_folder, 'nbZIFFF_sorted.data'),file_format="DATA")
    # Copy topology coefficients to nbZIFFF_sorted.data
    with open(os.path.join(output_folder, 'nbZIFFF.data'), 'r') as f:
        lines = f.readlines()
        line1=None
        line2=None
        for i in range(len(lines)):
            if lines[i].startswith('Bond Coeffs'):
                line1=i
            if lines[i].startswith('Atoms'):
                line2=i
        assert line1 is not None and line2 is not None
        content_to_copy=lines[line1:line2]
    with open(os.path.join(output_folder, 'nbZIFFF_sorted.data'), 'r') as f:
        lines_sorted=f.readlines()
        line_mark=None
        for i in range(len(lines_sorted)):
            if lines_sorted[i].startswith('Atoms'):
                line_mark=i
        assert line_mark is not None
    with open(os.path.join(output_folder, 'nbZIFFF_sorted.data'), 'w') as f:
        f.writelines(lines_sorted[0:line_mark]+content_to_copy+lines_sorted[line_mark:])
    # Clean up
    os.remove(os.path.join(output_folder, 'nbZIFFF.cif'))#Generated by pdb2cif
    os.remove(pdb2ciflog)#Generated by pdb2cif
    os.remove(os.path.join(output_folder, 'nbZIFFF_topol.cif'))#Generated by cif2lammps
    os.remove(os.path.join(output_folder, 'nbZIFFF.data'))#Generated by cif2lammps
    os.remove(os.path.join(output_folder, 'nbZIFFF.pdb'))#Generated by cif2lammps
    os.remove(cif2lammpslogpath)#Generated by cif2lammps
    os.remove(os.path.join(output_folder, 'atom_types_for_dump.txt'))#Generated by cif2lammps
    os.remove(os.path.join(output_folder, 'pair.txt'))#Generated by cif2lammps
    
def convert_atom_types(universe: MDAnalysis.Universe, target_format: str) -> MDAnalysis.Universe:
    """Convert atom types between string and integer representations.
    
    Parameters
    ----------
    universe : MDAnalysis.Universe
        Universe containing atoms whose types should be converted
    target_format : str
        Format to convert to - either 'str' or 'int'
        
    Returns
    -------
    MDAnalysis.Universe
        Universe with converted atom types
    """
    u_new=universe.copy()
    # Maps for basic atom types (C, H, N, Zn)
    sorted_atom_types={'C8': '1', 
   'O3': '2' , 
   'H5': '3' , 
   'Zn': '4' , 
   'He': '5' , 
   'H3': '6' , 
   'C2': '7' , 
   'H2': '8' , 
   'N1': '9' , 
   'C1': '10' , 
   'C3': '11' , 
   'Ne': '12'}
    sorted_atom_types_inv = {v: k for k, v in sorted_atom_types.items()}
    
    current_types = set(u_new.atoms.types)
    
    if current_types.issubset(sorted_atom_types.keys()):
        if target_format == "int":
            u_new.atoms.types = [sorted_atom_types[t] for t in u_new.atoms.types]
    elif current_types.issubset(sorted_atom_types_inv.keys()):
        if target_format == "str":
            u_new.atoms.types = [sorted_atom_types_inv[x] for x in u_new.atoms.types]
    else:
        raise ValueError(f"Unknown atom types: {current_types}")
        
    return u_new
